internal final class ETGAgreementTrackingReportController extends SrsReportRunController
{

}

Method.Source:
public static ETGAgreementTrackingReportController construct()
{
    return new ETGAgreementTrackingReportController();
}

public static void main(Args _args)
{
    ETGAgreementTrackingReportController controller = ETGAgreementTrackingReportController::construct();
    controller.parmArgs(_args);

    controller.parmReportName(ssrsReportStr(ETGAgreementTrackingReport, ReportMain));
    controller.startOperation();
}

public void preRunModifyContract()
{

    ETGAgreementTrackingReportContract contract = this.parmReportContract().parmRdpContract() as ETGAgreementTrackingReportContract;

    this.parmReportContract().parmReportName(this.getSelectedReportName(contract));
    super();

}

private str getSelectedReportName(ETGAgreementTrackingReportContract _contract)
{
    str reportNameLocal;
    if (_contract.parmQty())
    {
        reportNameLocal = ssrsReportStr(ETGAgreementTrackingReport, ReportQualityGroup);
    }
    else
    {
        reportNameLocal = ssrsReportStr(ETGAgreementTrackingReport, ReportMain);
    }
    return reportNameLocal;
}

